+/** Deliver structural relation events with their target to pair tracking modifiers. */
+function notifyPairTracking(
+    world: World,
+    entity: Entity,
+    trait: Trait,
+    target: Entity,
+    eventType: 'add' | 'remove'
+) {
+    const instance = getTraitInstance(world[$internal].traitInstances, trait);
+    if (!instance) return;
+    const { generationId, bitflag } = instance;
+    for (const query of instance.trackingQueries) {
+        const match =
+            query.relationFilters && query.relationFilters.length > 0
+                ? checkQueryTrackingWithRelations(world, query, entity, eventType, generationId, bitflag, target)
+                : query.checkTracking(world, entity, eventType, generationId, bitflag, target);
+        if (match) query.add(entity);
+        else query.remove(world, entity);
+    }
+}
