+/** Replace base relation snapshots with the data for the tracked relation target. */
+function resolvePairTrackedState(
+    world: World,
+    entity: Entity,
+    params: QueryParameter[],
+    state: any[]
+) {
+    let index = 0;
+    for (const param of params) {
+        if (isRelationPair(param)) {
+            const trait = param[$internal].relation[$internal].trait;
+            if (trait[$internal].type !== 'tag') state[index++] = getRelationData(world, entity, param[$internal].relation as Relation<Trait>, param[$internal].target as Entity);
+            continue;
+        }
+        if (isModifier(param)) {
+            if (param.type === 'not') continue;
+            for (const trait of param.traits) {
+                if (trait[$internal].type === 'tag') continue;
+                const pair = param.pairs?.find((candidate) => candidate[$internal].relation[$internal].trait === trait);
+                if (pair && typeof pair[$internal].target === 'number') {
+                    state[index] = getRelationData(world, entity, pair[$internal].relation as Relation<Trait>, pair[$internal].target);
+                }
+                index++;
+            }
+            continue;
+        }
+        if ((param as Trait)[$internal].type !== 'tag') index++;
+    }
+}
